import time
import functools
def retry_with_backoff(max_retries, base_delay):
    def decorator(f):
        @functools.wraps(f)
        def wrapper(*a, **k):
            delay = base_delay
            last_err = None
            for _ in range(max_retries):
                try: return f(*a, **k)
                except ValueError as e:
                    last_err = e
                    time.sleep(delay)
                    delay *= 2
            raise last_err
        return wrapper
    return decorator

