import heapq
def dijkstra(g, s):
    q = [(0, s)]; d = {s: 0}
    while q:
        (cost, n) = heapq.heappop(q)
        for nb, c in g.get(n, {}).items():
            nc = cost + c
            if nb not in d or nc < d[nb]: d[nb] = nc; heapq.heappush(q, (nc, nb))
    return d

